  1→use chrono::{DateTime, Utc};
  2→use uuid::Uuid;
  3→
  4→use super::todo_title::TodoTitle;
  5→use super::user::UserId;
  6→
  7→#[derive(Debug, Clone, PartialEq, Eq)]
  8→pub struct ProjectId(Uuid);
  9→
 10→impl Default for ProjectId {
 11→    fn default() -> Self {
 12→        Self::new()
 13→    }
 14→}
 15→
 16→impl ProjectId {
 17→    pub fn new() -> Self {
 18→        Self(Uuid::new_v4())
 19→    }
 20→
 21→    pub fn from_uuid(uuid: Uuid) -> Self {
 22→        Self(uuid)
 23→    }
 24→
 25→    pub fn as_uuid(&self) -> &Uuid {
 26→        &self.0
 27→    }
 28→}
 29→
 30→/// A multi-step outcome requiring two or more actions. Each project
 31→/// should have at least one next action to be considered "moving forward."
 32→/// Projects without a next action are "stalled."
 33→///
 34→/// State machine:
 35→///   Active --complete()--> Completed
 36→///   Active --drop()-----> Dropped
 37→///
 38→/// Completed and Dropped are terminal states.
 39→#[derive(Debug, Clone)]
 40→pub enum Project {
 41→    Active {
 42→        id: ProjectId,
 43→        user_id: UserId,
 44→        title: TodoTitle,
 45→        created_at: DateTime<Utc>,
 46→    },
 47→    Completed {
 48→        id: ProjectId,
 49→        user_id: UserId,
 50→        title: TodoTitle,
 51→        created_at: DateTime<Utc>,
 52→        completed_at: DateTime<Utc>,
 53→    },
 54→    Dropped {
 55→        id: ProjectId,
 56→        user_id: UserId,
 57→        title: TodoTitle,
 58→        created_at: DateTime<Utc>,
 59→        dropped_at: DateTime<Utc>,
 60→    },
 61→}
 62→
 63→impl Project {
 64→    pub fn new(user_id: UserId, title: TodoTitle) -> Self {
 65→        Self::Active {
 66→            id: ProjectId::new(),
 67→            user_id,
 68→            title,
 69→            created_at: Utc::now(),
 70→        }
 71→    }
 72→
 73→    pub fn from_parts(
 74→        id: ProjectId,
 75→        user_id: UserId,
 76→        title: TodoTitle,
 77→        created_at: DateTime<Utc>,
 78→        completed_at: Option<DateTime<Utc>>,
 79→        dropped_at: Option<DateTime<Utc>>,
 80→    ) -> Self {
 81→        if let Some(completed_at) = completed_at {
 82→            Self::Completed {
 83→                id,
 84→                user_id,
 85→                title,
 86→                created_at,
 87→                completed_at,
 88→            }
 89→        } else if let Some(dropped_at) = dropped_at {
 90→            Self::Dropped {
 91→                id,
 92→                user_id,
 93→                title,
 94→                created_at,
 95→                dropped_at,
 96→            }
 97→        } else {
 98→            Self::Active {
 99→                id,
100→                user_id,
101→                title,
102→                created_at,
103→            }
104→        }
105→    }
106→
107→    pub fn id(&self) -> &ProjectId {
108→        match self {
109→            Self::Active { id, .. } | Self::Completed { id, .. } | Self::Dropped { id, .. } => id,
110→        }
111→    }
112→
113→    pub fn user_id(&self) -> &UserId {
114→        match self {
115→            Self::Active { user_id, .. }
116→            | Self::Completed { user_id, .. }
117→            | Self::Dropped { user_id, .. } => user_id,
118→        }
119→    }
120→
121→    pub fn title(&self) -> &TodoTitle {
122→        match self {
123→            Self::Active { title, .. }
124→            | Self::Completed { title, .. }
125→            | Self::Dropped { title, .. } => title,
126→        }
127→    }
128→
129→    pub fn created_at(&self) -> &DateTime<Utc> {
130→        match self {
131→            Self::Active { created_at, .. }
132→            | Self::Completed { created_at, .. }
133→            | Self::Dropped { created_at, .. } => created_at,
134→        }
135→    }
136→
137→    pub fn is_active(&self) -> bool {
138→        matches!(self, Self::Active { .. })
139→    }
140→
141→    pub fn is_completed(&self) -> bool {
142→        matches!(self, Self::Completed { .. })
143→    }
144→
145→    pub fn is_dropped(&self) -> bool {
146→        matches!(self, Self::Dropped { .. })
147→    }
148→
149→    /// Transitions an Active project to Completed.
150→    /// If already completed or dropped, returns self unchanged.
151→    pub fn complete(self) -> Self {
152→        match self {
153→            Self::Active {
154→                id,
155→                user_id,
156→                title,
157→                created_at,
158→            } => Self::Completed {
159→                id,
160→                user_id,
161→                title,
162→                created_at,
163→                completed_at: Utc::now(),
164→            },
165→            other => other,
166→        }
167→    }
168→
169→    /// Transitions an Active project to Dropped.
170→    /// If already completed or dropped, returns self unchanged.
171→    pub fn drop_project(self) -> Self {
172→        match self {
173→            Self::Active {
174→                id,
175→                user_id,
176→                title,
177→                created_at,
178→            } => Self::Dropped {
179→                id,
180→                user_id,
181→                title,
182→                created_at,
183→                dropped_at: Utc::now(),
184→            },
185→            other => other,
186→        }
187→    }
188→}
